from flask import Flask, request, jsonify
from pymongo import MongoClient

app = Flask(__name__)

# Connect to MongoDB
client = MongoClient('localhost', 27017)
db = client['cms']

# User profile collection
users = db['users']

# Document collection
documents = db['documents']

# Aggregate documents by category
@app.route('/aggregate_documents', methods=['GET'])
def aggregate_documents():
    pipeline = [
        {'$match': {}},
        {'$group': {'_id': '$category', 'count': {'$sum': 1}}}
    ]
    results = documents.aggregate(pipeline)
    return jsonify(list(results))

# Query documents by category
@app.route('/query_documents', methods=['GET'])
def query_documents():
    category = request.args.get('category')
    results = documents.find({'category': category})
    return jsonify(list(results))

# Store user profile
@app.route('/store_profile', methods=['POST'])
def store_profile():
    data = request.json
    users.insert_one(data)
    return jsonify({'message': 'User profile stored successfully.'})

if __name__ == '__main__':
    app.run(debug=True)